func errorHandlerReply(w http.ResponseWriter, r *http.Request, err error) {
	switch e := err.(type) {
	case *api.RequiredParamError:
		err := fmt.Errorf("required param missing %s: %w", e.ParamName, err)
		models.NewStatusProblem(r.Context(), err, http.StatusBadRequest).Respond(w)
	default:
		err := fmt.Errorf("unhandled server error: %w", err)
		models.NewStatusProblem(r.Context(), err, http.StatusInternalServerError).Respond(w)
	}
}

func (h *NamespaceHandler) CreateNamespace(ctx context.Context, ns string) error {
	return transaction.RunWithNoValue(ctx, h.transactionManager, func(ctx context.Context) error {
		listed, err := h.service.ListTaxCodes(ctx, ListTaxCodesInput{Namespace: ns})
		if err != nil {
			return fmt.Errorf("list tax codes: %w", err)
		}
		existingByKey := lo.SliceToMap(listed.Items, func(tc TaxCode) (string, TaxCode) { return tc.Key, tc })
		var invoicingID, creditGrantID string
		for _, seed := range h.seeds {
			id, err := h.ensureTaxCode(ctx, ns, seed, existingByKey)
			if err != nil {
				return fmt.Errorf("seed tax code %q: %w", seed.Key, err)
			}
			if seed.DefaultInvoicing { invoicingID = id }
			if seed.DefaultCreditGrant { creditGrantID = id }
		}
		return nil
	})
}

var (
	_ ConfigMapper    = (*ProducerConfigParams)(nil)
	_ ConfigValidator = (*ProducerConfigParams)(nil)
)

type ProducerConfigParams struct {
	Partitioner Partitioner
}

func (p ProducerConfigParams) Validate() error {
	if p.Partitioner != "" && !slices.Contains(PartitionerValues, p.Partitioner) {
		return errors.New("invalid partitioner config")
	}
	return nil
}

func (p ProducerConfigParams) AsConfigMap() (kafka.ConfigMap, error) {
	m := kafka.ConfigMap{"go.logs.channel.enable": true}
	if p.Partitioner != "" {
		if err := m.SetKey("partitioner", p.Partitioner); err != nil {
			return nil, err
		}
	}
	return m, nil
}
